// @n8n-evol-I:primitive — exempt from pure-function discipline
// Active cleanup: iterate every scope the env has registered, GET its :meta
// sidecar, and DEL the pair only when the meta's execution_id matches the
// failed execution.
//
// `lockScopes` is read from <env>.yml and is expected to be an array of scope
// strings (the post-prefix portion — e.g. ['excel-sharepoint', 'cms-row']).
// add_lock_to_workflow.py auto-registers static --scope-expression values
// here; dynamic scopes are skipped and require manual lockScopes entries.
let LOCK_SCOPES;
try {
  LOCK_SCOPES = {{@:env:lockScopes}};
} catch (e) {
  LOCK_SCOPES = [];
}
if (!Array.isArray(LOCK_SCOPES)) LOCK_SCOPES = [];

const errorData = $('Error Trigger').first().json || {};
const failed_execution_id = errorData.execution?.id || errorData.executionId || $execution.id || 'unknown';
const failed_workflow_id = errorData.workflow?.id || 'unknown';
const failed_workflow_name = errorData.workflow?.name || 'unknown';
const failed_error_message = errorData.execution?.error?.message || errorData.error?.message || 'unknown';

if (LOCK_SCOPES.length === 0) {
  // Graceful no-op: no scopes registered → nothing to clean. Avoids errors
  // and surfaces the configuration gap to the operator via the log entry.
  return [{
    json: {
      cleaned: false,
      reason: 'no lockScopes registered in env yaml — add to lockScopes list to enable active cleanup',
      failed_execution_id,
      failed_workflow_id,
      failed_workflow_name,
      failed_error_message,
      cleanup_terminal: true,
    },
  }];
}

return LOCK_SCOPES.map(scope => ({
  json: {
    scope,
    key: `n8n-lock-${scope}`,
    meta_key: `n8n-lock-${scope}:meta`,
    failed_execution_id,
    failed_workflow_id,
    failed_workflow_name,
    failed_error_message,
    cleanup_terminal: false,
  },
}));

// @n8n-evol-I:primitive — exempt from pure-function discipline
// For each scope, parse meta and keep only those owned by the failed execution.
// Output is a list of {scope, key, meta_key} for cleanup; empty list is fine.
const items = $input.all();
const scopeItems = $('Prepare Scope List').all();
const toRelease = [];
for (let i = 0; i < items.length; i++) {
  const lockValue = items[i].json.LOCK_META;
  const scopeData = scopeItems[i] && scopeItems[i].json;
  if (!scopeData || !lockValue) continue;
  let parsedLock;
  try {
    parsedLock = JSON.parse(lockValue);
  } catch (e) {
    continue;
  }
  if (parsedLock && parsedLock.execution_id === scopeData.failed_execution_id) {
    toRelease.push({
      json: {
        should_release: true,
        scope: scopeData.scope,
        key: scopeData.key,
        meta_key: scopeData.meta_key,
        lock_id: parsedLock.lock_id,
        locked_at: parsedLock.locked_at,
        lock_workflow_name: parsedLock.workflow_name,
        failed_execution_id: scopeData.failed_execution_id,
        failed_workflow_id: scopeData.failed_workflow_id,
        failed_workflow_name: scopeData.failed_workflow_name,
        failed_error_message: scopeData.failed_error_message,
      },
    });
  }
}
if (toRelease.length === 0) {
  return [{ json: { cleaned: false, reason: 'no locks owned by failed execution', cleanup_terminal: true } }];
}
return toRelease;

// @n8n-evol-I:primitive — exempt from pure-function discipline
const items = $input.all();
return [{
  json: {
    cleaned: items.length > 0 && items[0].json.should_release === true,
    cleaned_count: items.filter(i => i.json.should_release === true).length,
    scopes: items.map(i => i.json.scope).filter(Boolean),
  },
}];
